"url:mojo/neapolitan/widgets/templates/imageRow.html":'\x3cdiv class\x3d"relative"\x3e\n    \x3cul class\x3d\'mojoImageList\' data-dojo-attach-point\x3d"imageList"\x3e\x3c/ul\x3e\n    \x3cdiv data-dojo-attach-point\x3d"uploadOverlay" class\x3d"alignc mojoImageListOverlay"\x3e\n        \x3cb\x3eHang on, we\x26rsquo;re uploading here...\x3c/b\x3e\x3cbr /\x3e\x3cimg src\x3d"/images/loading_bar.gif" class\x3d"rounded3" /\x3e\n    \x3c/div\x3e\n\x3c/div\x3e',"url:mojo/neapolitan/widgets/templates/imageListItem.html":'\x3cli class\x3d"mojoImageItem dojoDndItem" dndType\x3d"dndImageListItem" data-image-index\x3d{{index}}\x3e\n    {% if multipleImages %}\n    \x3cdiv class\x3d"mojoItemListItemHandle icon24 icon-vdrag_24 imgrpl-inline dojoDndHandle" title\x3d"Drag to Sort"\x3e\x3cspan class\x3d"freddicon vellip"\x3e\x3c/span\x3e\x3c/div\x3e\n    {% endif %}\n\n    {% if image %}\n    \x3cimg class\x3d"mojoImageItemIcon float-left" src\x3d"{{image.src}}"\x3e\n    {% else %}\n    \x3cimg class\x3d"mojoImageItemIcon float-left" src\x3d"/images/icons/empty_image-600.png"\x3e\n    {% endif %}\n\n    \x3cdiv class\x3d"mojoImageItemMeta"\x3e\n        \x3cstrong class\x3d"wsnormal" data-image-title\x3d""\x3e{{title}}\x3c/strong\x3e\n        \x3cdiv class\x3d"small-meta" data-image-subtitle\x3d""\x3e{{subtitle}}\x3c/div\x3e\n\n        {% if image %}\n            {% if image.width %}{% if image.height %}\n            \x3cdiv class\x3d"small-meta"\x3e{{image.width}} \x26times; {{image.height}}\x3c/div\x3e\n            {% endif %}{% endif %}\n        {% endif %}\n\n        \x3cul class\x3d"linear-list mojoImageListActions small-meta dots"\x3e\n        {% if image %}\n            \x3cli\x3e\x3ca data-action-type\x3d"browse" href\x3d"#"\x3eReplace\x3c/a\x3e\x3c/li\x3e\n            \x3cli\x3e\x3ca data-action-type\x3d"aviary" href\x3d"#"\x3eEdit\x3c/a\x3e\x3c/li\x3e\n            {% if canAddLink %}\n            \x3cli\x3e\x3ca data-action-type\x3d"link" href\x3d"#"\x3eLink\x3c/a\x3e\x3c/li\x3e\n            {% endif %}\n            {% if canAddAlt %}\n            \x3cli\x3e\x3ca data-action-type\x3d"altText" href\x3d"#"\x3eAlt\x3c/a\x3e\x3c/li\x3e\n            {% endif %}\n        {% else %}\n            \x3cli\x3e\x3ca data-action-type\x3d"browse" href\x3d"#"\x3eBrowse\x3c/a\x3e\x3c/li\x3e\n        {% endif %}\n\n        {% if canBeDeleted %}\n            \x3cli\x3e\x3ca data-action-type\x3d"remove" href\x3d"#"\x3eRemove\x3c/a\x3e\x3c/li\x3e\n        {% endif %}\n        \x3c/ul\x3e\n    \x3c/div\x3e\n    \x3cdiv class\x3d"clear"\x3e\x3c/div\x3e\n    \x3cdiv class\x3d"imageAlt selfclear hide pad-lv2 pad-lr0"\x3e\n        \x3clabel for\x3d"imagealt_{{domId}}_{{index}}"\x3eImage Alt-Text \x3cspan class\x3d"small-meta"\x3e(\x3ca href\x3d"http://kb.mailchimp.com/article/what-is-alt-text" target\x3d"_blank"\x3eWhat\'s this?\x3c/a\x3e)\x3c/span\x3e\x3c/label\x3e\n        \x3cinput type\x3d"text" class\x3d"float-left altTextInput" style\x3d"width:60%;" id\x3d"imagealt_{{domId}}_{{index}}" value\x3d"{{image.alt|default:\'\'}}"\x3e\n        \x3ca class\x3d"button-small updateAltBtn float-left mar-lv2 mar-tb0 mar-r0" href\x3d"#"\x3eUpdate\x3c/a\x3e\n    \x3c/div\x3e\n    {% if tooWide %}\n    \x3cdiv class\x3d"feedback-block warning small-meta above-below15 pad-lv3 mar-lv2 mar-l0"\x3eThis image is so big it may obliterate inboxes. Images should be around 600px to 800px wide. \x3ca href\x3d"#" data-action-type\x3d"resize"\x3eLet\'s fix it\x3c/a\x3e.\x3c/div\x3e\n    {% endif %}\n    {% if image.correctResolution %}\n    \x3cdiv class\x3d"feedback-block warning small-meta above-below15 pad-lv3 mar-lv2 mar-l0"\x3eThe proportions of this image differ from the one next to it. \x3ca href\x3d"#" data-action-type\x3d"crop"\x3eLet\'s fix it\x3c/a\x3e.\x3c/div\x3e\n    {% endif %}\n    {% if image.tooNarrow %}\n    \x3cdiv class\x3d"feedback-block warning small-meta above-below15 pad-lv3 mar-lv2 mar-l0"\x3eOops, this image is too small for this space. Please upload a larger version that is at least 600px wide.\x3c/div\x3e\n    {% endif %}\n\x3c/li\x3e',
"url:mojo/signup-forms/templates/form.html":'\x3cdiv class\x3d"modalContent"\x3e\n    \x3cdiv class\x3d"flash-block" data-dojo-attach-point\x3d"formResponseMessages"\x3e\x3c/div\x3e\n    \x3cdiv class\x3d"modalContent__content" data-dojo-attach-point\x3d"formContentContainer"\x3e\n        \n        \x3c!-- Title \x26 Description - Holds HTML from CK editor --\x3e\n        \x3cdiv class\x3d"content__titleDescription" data-dojo-attach-point\x3d"descriptionContainer"\x3e\x3c/div\x3e\n\n        \x3c!-- Form Fields --\x3e\n\t\t\x3cform action\x3d"${subscribeUrl}" accept-charset\x3d"UTF-8" method\x3d"post" enctype\x3d"multipart/form-data" data-dojo-attach-point\x3d"formNode" novalidate\x3e\n\t\t\t\x3cdiv class\x3d"content__formFields" data-dojo-attach-point\x3d"formFieldsContainer"\x3e\x3c/div\x3e\n\t\t    \x3cdiv class\x3d"content__button"\x3e\n\t\t        \x3cinput class\x3d"button" type\x3d"submit" value\x3d"${buttonLabel}" data-dojo-attach-point\x3d"submitButton"/\x3e\n\t\t    \x3c/div\x3e\n\t\t\x3c/form\x3e\n\n        \x3c!-- Footer - Holds HTML from CK editor --\x3e\n        \x3cdiv class\x3d"content__footer" data-dojo-attach-point\x3d"footerContainer"\x3e\x3c/div\x3e\n    \x3c/div\x3e\n    \x3cdiv class\x3d"modalContent__image" data-dojo-attach-point\x3d"formImageContainer"\x3e\x3c/div\x3e\n\x3c/div\x3e',
"url:mojo/signup-forms/inputs/templates/Text.html":'\x3cdiv class\x3d"field-wrapper"\x3e\n\t\x3clabel for\x3d"mc-${name}"\x3e${label}\x3c/label\x3e\n\t\x3cinput type\x3d"text" name\x3d"${name}" value\x3d"" id\x3d"mc-${name}" /\x3e\n\x3c/div\x3e',"url:mojo/signup-forms/inputs/templates/Address.html":'\x3cdiv class\x3d"field-wrapper address"\x3e\n\t\x3cdiv\x3e\n\t    \x3clabel for\x3d"mc-${name}-addr1"\x3e${label}\x3c/label\x3e\n\t\t\x3cinput class\x3d"address1" type\x3d"text" name\x3d"${name}[addr1]" value\x3d"" id\x3d"mc-${name}-addr1" data-dojo-attach-point\x3d"address1Node" /\x3e\n\t\x3c/div\x3e\n\t\x3cdiv\x3e\n\t    \x3clabel for\x3d"mc-${name}-addr2"\x3eAddress Line 2\x3c/label\x3e\n\t\t\x3cinput class\x3d"address2" type\x3d"text" name\x3d"${name}[addr2]" value\x3d"" id\x3d"mc-${name}-addr2" /\x3e\n\t\x3c/div\x3e\n\t\x3cdiv\x3e\n\t    \x3clabel for\x3d"mc-${name}-city"\x3eCity\x3c/label\x3e\n\t\t\x3cinput class\x3d"city" type\x3d"text" name\x3d"${name}[city]" value\x3d"" id\x3d"mc-${name}-city" data-dojo-attach-point\x3d"cityNode" /\x3e\n\t\x3c/div\x3e\n\t\x3cdiv\x3e\n\t    \x3clabel for\x3d"mc-${name}-state"\x3eState/Province/Region\x3c/label\x3e\n\t\t\x3cinput class\x3d"state" type\x3d"text" name\x3d"${name}[state]" value\x3d"" id\x3d"mc-${name}-state" data-dojo-attach-point\x3d"stateNode" /\x3e\n\t\x3c/div\x3e\n\t\x3cdiv\x3e\n\t    \x3clabel for\x3d"mc-${name}-zip"\x3ePostal / Zip Code\x3c/label\x3e\n\t\t\x3cinput class\x3d"zip" type\x3d"text" name\x3d"${name}[zip]" value\x3d"" id\x3d"mc-${name}-zip" data-dojo-attach-point\x3d"zipNode" /\x3e\n\t\x3c/div\x3e\n\t\x3cdiv\x3e\n\t    \x3clabel for\x3d"mc-${name}-country"\x3eCountry\x3c/label\x3e\n\t    \x3c!-- TODO: Is there a formatting option for which country should be top of the list? --\x3e\n\t\t\x3cselect class\x3d"country" name\x3d"${name}[country]" id\x3d"mc-${name}-country" data-dojo-attach-point\x3d"countrySelectNode"\x3e\n\t\t    \x3coption value\x3d"" selected\x3e\x3c/option\x3e\n\t\t    \x3coption value\x3d"164"\x3eUSA\x3c/option\x3e\n\t\t\x3c/select\x3e\n\t\x3c/div\x3e\n\x3c/div\x3e',
